// Type declarations for the @generated CMS bundle artifact
// (cms-bundle.generated.js, produced by scripts/build-cms-bundle.mjs).
// TS pairs this `.d.ts` with the sibling `.js` by filename, so importing
// "./cms-bundle.generated.js" resolves to these types even on a fresh checkout
// where the generated `.js` may be absent.
export const builtAt: string;
export const mainModule: string;
export const files: Record<string, string>;
